export async function transform({ input, createDocumentModel, createParagraph }) {
  return createDocumentModel({
    title: input?.title || "Local OCR Basic Patch",
    sourceFormat: "local-ocr-plugin",
    blocks: [createParagraph("Local OCR patch placeholder: install the optional local model bundle for real OCR extraction.")],
    metadata: { plugin: { id: "local-ocr-basic", patch: true, localOnly: true, modelRequired: true } }
  });
}
